import{_ as t,o,c as r,a3 as s}from"./chunks/framework.CjquFG0V.js";const d=JSON.parse('{"title":"201A. Rosters","description":"","frontmatter":{"title":"201A. Rosters","eba":"Mental Health Services 2024-2028","topics":["hours","rosters","preliminary"]},"headers":[],"relativePath":"ebas/mental-health/management-admin/hours-of-work/201A-rosters.md","filePath":"ebas/mental-health/management-admin/hours-of-work/201A-rosters.md"}'),n={name:"ebas/mental-health/management-admin/hours-of-work/201A-rosters.md"};function a(i,e,l,h,p,c){return o(),r("div",null,[...e[0]||(e[0]=[s('<h1 id="_201a-rosters" tabindex="-1">201A. Rosters <a class="header-anchor" href="#_201a-rosters" aria-label="Permalink to &quot;201A. Rosters&quot;">​</a></h1><p>201A.1. Where an Employee works a set arrangement of hours without change, then no roster is required to be established. 201A.2. A roster of at least 28 days&#39; duration shall be posted at least 28 days before it comes into operation at each work location in a place where it may be readily seen by such Employees and the Secretary or other accredited representative of HACSU. 201A.3. This 28 day roster provision will operate from the next roster cycle commencing 3 months after the commencement of this Agreement. 201A.4. Roster Requirements</p><p><strong>(a)</strong> Rosters will set out:</p><p><strong>(i)</strong> The Employees&#39; daily ordinary working hours</p><p><strong>(ii)</strong> Starting and finishing time</p><p><strong>(iii)</strong> Meal intervals hours of work, start times, finish times and meal intervals.</p><p><strong>(b)</strong> Provide an Employee who works 0.8 EFT or more with two consecutive days off per week. Nothing in this subclause (b) is intended to:</p><p><strong>(i)</strong> restrict an Employee requesting single days off, including as a self- rostering request; or</p><p><strong>(ii)</strong> prevent an Employee who works 0.8 EFT or more from having a single day off rostered where they also have consecutive days off rostered that week.</p><p><strong>(c)</strong> An Employer may use an alternative method to record meal interval allocations outlined in 201A.4(iii) if the electronic roster system being used is unable to accommodate its inclusion. This will be located in each work location where it can be readily accessible seen by such Employees and/or other representative of the Union(s) to ensure compliance with meal break provisions, for a period of no less than 6 years.</p><p>201A.5. Rosters which include work on public holiday</p><p><strong>(a)</strong> Employers must implement a policy or procedure for the issuance and finalisation of rosters which cover the performance of work on a public holiday under the Act.</p><p><strong>(b)</strong> The policy/procedure referenced at subclause 201A.5(a)above should:</p><p><strong>(i)</strong> set out the process for an Employee to request not to work on a public holiday they are requested to work; and</p><p><strong>(ii)</strong> set out the process for the Employer to provide a written response to an Employee&#39;s request not to work on a public holiday they are requested to work</p><p><strong>(c)</strong> An Employer who receives a request under subclause 201A.5(b)(i) must accept that request unless the Employer determines that the refusal is not reasonable in the circumstances. The factors an Employer must consider when determining whether a request is not reasonable include:</p><p><strong>(i)</strong> whether the Employee has clearly explained a reason for refusing to work on the relevant public holiday</p><p><strong>(ii)</strong> the nature of the Employers&#39; workplace or enterprise (including its operational requirements), and the nature of the work performed by the Employee</p><p><strong>(iii)</strong> the capacity for the Employer to find a replacement Employee to perform the same work</p><p><strong>(iv)</strong> the Employee&#39;s personal circumstances (including family responsibilities) to the extent that those circumstances have been disclosed to the Employer</p><p><strong>(v)</strong> whether the Employee could reasonably have expected the Employer to request that they work on the public holiday(s)</p><p><strong>(vi)</strong> whether the Employee is entitled to receive overtime payments, penalty rates or other compensation for, or a level of remuneration that reflects expectation of, work on the public holiday(s)</p><p><strong>(vii)</strong> the type of employment of the Employee (e.g. whether full-time, part- time, casual or shiftwork)</p><p><strong>(viii)</strong> the amount of notice in advance of the public holiday given by the Employer when making the request</p><p><strong>(ix)</strong> the amount of notice in advance of the public holiday given by the Employee when refusing the request</p><p><strong>(x)</strong> the number of public holidays the Employee has previously worked and been required to work in recent roster durations; and</p><p><strong>(xi)</strong> any other relevant matter.</p><p><strong>(d)</strong> Where the Employer has requested an Employee to work any public holiday(s) and either:</p><p><strong>(i)</strong> the Employee has not made a request not to work the public holiday in accordance with the policy or procedure referenced at subclause 201A.5(b)) above; or</p><p><strong>(ii)</strong> the Employer has determined that a request was not reasonable (taking into account the factors in subclause 201A.5(c) the Employer may require the Employee to work on the relevant public holiday(s).</p><p>Plain language terms: rostering, shift roster, duty roster, roster changes.</p>',31)])])}const u=t(n,[["render",a]]);export{d as __pageData,u as default};
